// v6.0.21: read from /process_url (universal)
const parse = $('Code — Parse Command v6.0.27').first().json;
let url = parse.url;
if (parse.cmd === 'channel') {
  try {
    const latest = $('Code — Fetch latest from channel').first().json;
    if (latest && !latest.skip) {
      url = latest.full_url;
    }
  } catch (e) {}
}
const subs = $('HTTP /process_url').first().json;
const prof = $('HTTP /user_profile').first().json.profile || {};
return [{json: {
  chat_id: parse.chat_id,
  user_id: parse.user_id,
  message_id: parse.message_id,
  text: subs.text ? subs.text.slice(0, 8000) : '',
  system: '',
  user_profile: prof,
  timeline: subs.timeline || [],
  meta: subs.meta || {},
  // for /comments_analyze:
  comments: subs.comments || [],
  // for digest:
  video_id: subs.video_id || '',
  platform: subs.platform || 'unknown',
  method: subs.method || 'unknown',
  // for ack feedback:
  title: subs.title || 'video',
  duration: subs.duration || 0,
  char_count: subs.char_count || 0,
  // body for downstream:
  body: parse
}}];

// v6.0.21: build digest (universal) + comments analysis
const yagpt = $('HTTP /yagpt_summarize (chunking внутри)').first().json;
const parsed = yagpt.parsed || {};
// v6.0.21: subs from /process_url (universal)
let subs = null;
try { subs = $('HTTP /process_url').first().json; } catch (e) {}
// v6.0.21: comments analysis
let commentsAnalysis = null;
try { commentsAnalysis = $('HTTP /comments_analyze').first().json; } catch (e) {}
// v6.0.21: build can be either YandexGPT payload (fetch) or media YandexGPT payload (media)
let build = null;
try { build = $('Code — Build YandexGPT payload').first().json; } catch (e) {}
if (!build) {
  try { build = $('Code — Build media YandexGPT payload').first().json; } catch (e) {}
}
const parse = $('Code — Parse Command v6.0.27').first().json;
const url = (parse && parse.url) || (build && build.url) || 'https://example.com';
const videoId = (subs && subs.video_id) || (build && build.meta && build.meta.video_id) || '';
return [{json: {
  url: url,
  video_id: videoId,
  title: (build && build.meta && build.meta.title) || (subs && subs.title) || (subs && subs.meta && subs.meta.title) || 'Media transcription',
  summary: parsed.summary || [],
  actions: parsed.actions || [],
  // v6.0.21: drop claims_yagpt
  // claims_yagpt: parsed.claims || [],
  claims: (subs && subs.claims) || [],
  comments: (subs && subs.comments) || [],
  // v6.0.21: add comments analysis results
  comments_summary: (commentsAnalysis && commentsAnalysis.comments_summary) || [],
  top_valuable: (commentsAnalysis && commentsAnalysis.top_valuable) || [],
  meta: (subs && subs.meta) || (build && build.meta) || {},
  chat_id: (build && build.chat_id) || (parse && parse.chat_id) || 0,
  user_id: (build && build.user_id) || (parse && parse.user_id) || 0,
  relevance: parsed.relevance || 'on_topic'
}}];

// v6.0.27: deduped → silent respond
const _deduped = items[0] && items[0].json && items[0].json.deduped;
if (_deduped) {
  return [{json: {chat_id: '261540559', text: '', silent: true, message_id: 0}}];
}
// v6.0.26: актуальное меню + inline buttons
const parse = $('Code — Parse Command v6.0.27').first().json || items[0].json || {};
let text = '';
let buttons = null;
if (parse.cmd === 'help' || parse.cmd === 'start') {
  text = `🤖 Research Agent v6.0.26

📹 Поддерживаю ссылки:
• YouTube (youtu.be/, /watch, /shorts, /live)
• Rutube
• VK (видео + клипы)
• Kinescope
• Vimeo, PeerTube, Dzen, VKPlay, Smotrim
• Подкасты (Apple, Google, SoundCloud)
• Аудио/фото/видео в чате → транскрибирую

⚙️ Что делаю с ссылкой:
1. Скачиваю субтитры (или Newton transcribe)
2. Саммари + action items через YandexGPT
3. Топ-комментарии (YouTube/Rutube)
4. Сохраняю в личную базу знаний
5. Возвращаю HTML-документ + TL;DR

💰 ~1₽/дайджест, бюджет 200₽/день

🎛 Дополнительно (кнопки ниже):
• 📊 Статистика — счётчики
• 🕐 Последние — 5 дайджестов
• ⏳ Pending — невыполненные actions
• 🎙 Аудио — MP3 голосом Бурунова
• 📖 Справка — подробнее`;
  buttons = {
    inline_keyboard: [
      [
        {text: '📊 Статистика', callback_data: 'stats'},
        {text: '🕐 Последние', callback_data: 'recent'},
      ],
      [
        {text: '⏳ Pending', callback_data: 'pending'},
        {text: '🎙 Аудио', callback_data: 'audio_last'},
      ],
      [
        {text: '📖 Справка', callback_data: 'help_docs'},
        {text: '✖ Закрыть', callback_data: 'close_menu'},
      ],
    ]
  };
} else if (parse.cmd === 'invalid') {
  text = '❌ ' + (parse.error_msg || 'Не понимаю эту ссылку.') + '\n\nПришли ссылку или нажми /help для меню.';
  buttons = {inline_keyboard: [[{text: '📖 Справка', callback_data: 'help_docs'}, {text: '✖ Закрыть', callback_data: 'close_menu'}]]};
} else {
  text = '🤔 Не понял. Пришли ссылку или /help.';
  buttons = {inline_keyboard: [[{text: '📖 Справка', callback_data: 'help_docs'}, {text: '✖ Закрыть', callback_data: 'close_menu'}]]};
}
const out = [];
for (const it of (items.length ? items : [{json:{}}])) {
  out.push({json: {
    chat_id: parse.chat_id || it.json.chat_id || '261540559',
    text: text,
    message_id: parse.message_id || it.json.message_id,
    reply_markup: buttons ? JSON.stringify(buttons) : null,
  }});
}
return out;

// v6.0.18: take channel_latest response and set url + user_msg
const r = $('HTTP /youtube_channel_latest').first().json;
const parse = $('Code — Parse Command v6.0.27').first().json;
let url = '';
let user_msg = '';
if (r.ok && r.url) {
  url = r.url;
  user_msg = '🎬 Беру последнее видео с канала: ' + url + (r.title ? '\n\n' + r.title : '');
} else {
  user_msg = '❌ Не нашёл видео на канале: ' + (r.error || 'unknown error');
}
return [{json: {
  url: url,
  user_msg: user_msg,
  chat_id: parse.chat_id,
  message_id: parse.message_id
}}];

// v6.0.18: only pass through if url is set
if (!items[0].json.url) {
  return [];
}
return items;

// v6.0.19: build 'processing media' message
const parse = $('Code — Parse Command v6.0.27').first().json;
const m = parse.media;
if (!m) return [{json: {chat_id: 0, text: 'no media'}}];
const dur = m.duration ? ` (${m.duration} сек)` : '';
const size_kb = m.file_size ? `, ${Math.round(m.file_size/1024)} KB` : '';
const kind_ru = {voice: 'голосовое', audio: 'аудио', video: 'видео', video_note: 'видео-кружочек'}[m.kind] || 'файл';
return [{json: {
  chat_id: parse.chat_id,
  text: '🎙 Обрабатываю ' + kind_ru + dur + size_kb + ' через Newton...'
}}];

// v6.0.19: build YandexGPT payload from media transcription
const parse = $('Code — Parse Command v6.0.27').first().json;
const subs = $('HTTP /transcribe').first().json;
const text = subs.text || '';
if (!text.trim()) {
  return [{json: {
    chat_id: parse.chat_id,
    user_id: parse.user_id,
    message_id: parse.message_id,
    cmd: 'media_empty',
    error: 'Newton вернул пустой текст. Возможно, в аудио нет речи.',
    user_profile: {},  // fallback empty profile
    text: '',
    system: '',
    timeline: [],
    meta: {
      source: 'media_' + (parse.media ? parse.media.kind : 'unknown'),
      file_size: parse.media ? parse.media.file_size : 0,
      duration: parse.media ? parse.media.duration : 0
    }
  }}];
}
// Don't use HTTP /user_profile - we can use a default profile from Parse
// v6.0.19: minimal profile from /user_profile will be merged later
return [{json: {
  chat_id: parse.chat_id,
  user_id: parse.user_id,
  message_id: parse.message_id,
  cmd: 'media',
  text: text.slice(0, 8000),
  system: '',
  user_profile: {name: parse.user_id, context: 'media transcription'},  // placeholder
  timeline: [],
  meta: {
    source: 'media_' + (parse.media ? parse.media.kind : 'unknown'),
    file_size: parse.media ? parse.media.file_size : 0,
    duration: parse.media ? parse.media.duration : 0
  }
}}];

// v6.0.19: notify user that media was empty
const r = $('Code — Build media YandexGPT payload').first().json;
return [{json: {
  chat_id: r.chat_id,
  text: '❌ ' + (r.error || 'Не удалось обработать файл')
}}];

// v6.0.21 FINAL: ack only if _route=fetch
const items = $input.all();
const out = [];
for (const item of items) {
  const j = item.json || {};
  const route = j._route || '';
  if (route === 'fetch') {
    out.push({ json: { ...j, ack_text: j.ack_text || 'Понял, обрабатываю ссылку...', ack_skipped: false } });
  }
}
return out;

// v6.0.24: pass through with body merged + write_audio=true for non-YT
const items = $input.all();
const out = [];
for (const item of items) {
  const j = item.json || {};
  const pc = $('Code — Parse Command v6.0.27').first().json || {};
  const url = j.url || pc.url || '';
  // For non-YouTube platforms, enable write_audio (Newton fallback)
  const isYT = /youtu\.?be/.test(url) || /youtube\.com/.test(url);
  const write_audio = !isYT;
  out.push({ json: {
    user_id: j.user_id || pc.user_id || '261540559',
    chat_id: j.chat_id || pc.chat_id || '261540559',
    message_id: j.message_id || pc.message_id || null,
    cmd: 'fetch',
    url: url,
    text: j.text || pc.raw || '',
    media: null,
    write_audio: write_audio,
    newton_fetch: false,
    body: { message: { text: url, chat: { id: parseInt(j.chat_id || pc.chat_id || '261540559') } } }
  } });
}
return out;

// v6.0.23: close menu (deleteMessage)
const items = $input.all();
const out = [];
for (const item of items) {
  const j = item.json || {};
  const chat_id = j.chat_id || '261540559';
  const message_id = j.message_id || 0;
  out.push({ json: {
    user_id: j.user_id || '261540559',
    chat_id: chat_id,
    message_id: message_id,
    body: { chat_id: chat_id, message_id: message_id }
  } });
}
return out;

// v6.0.26: build callback payload + set _action for SWITCH
const items = $input.all();
const out = [];
for (const item of items) {
  const j = item.json || {};
  const cb_data = j.callback_data || '';
  const user_id = j.user_id || '261540559';
  const chat_id = j.chat_id || '261540559';
  const message_id = j.message_id || null;

  let _action = 'fallback';
  if (cb_data === 'stats') _action = 'stats';
  else if (cb_data === 'recent') _action = 'recent';
  else if (cb_data === 'pending') _action = 'pending';
  else if (cb_data === 'audio_last') _action = 'audio_last';
  else if (cb_data === 'close_menu') _action = 'close_menu';
  else if (cb_data.startsWith('help_')) _action = 'help_topic';

  const url = 'http://host.docker.internal:8080/handle_callback';
  const body = {
    callback_query: {
      id: j.callback_id || '',
      data: cb_data,
      from: { id: user_id },
      message: { message_id: message_id, chat: { id: chat_id } }
    }
  };
  out.push({ json: {
    url,
    body,
    cb_data,
    _action,
    user_id: String(user_id),
    chat_id: String(chat_id),
    message_id,
    action: _action
  } });
}
return out;

// v6.0.23: format callback result — read _action from Build callback payload
const items = $input.all();
const out = [];
for (const item of items) {
  const j = item.json || {};
  // Get action from Build callback payload which has _action
  const ctx = $('Code — Build callback payload v6.0.21').first().json || {};
  const action = ctx._action || '';
  const user_id = ctx.user_id || '261540559';
  const chat_id = ctx.chat_id || '261540559';
  let text = '';
  if (action === 'stats') {
    const s = (j.stats || {});
    text = '📊 Статистика (user_id=' + user_id + '):\n\n' +
           '📚 Дайджестов: ' + (s.digests_count || 0) + '\n' +
           '🎯 Actions: ' + (s.actions_count || 0) + ' (pending: ' + (s.pending_actions || 0) + ')\n' +
           '📝 Символов: ' + (s.total_chars || 0);
  } else if (action === 'recent') {
    const ds = (j.digests || []);
    if (!ds.length) {
      text = '🕐 Пока нет дайджестов.';
    } else {
      text = '🕐 Последние ' + ds.length + ' дайджестов:\n\n';
      for (let i = 0; i < ds.length; i++) {
        const d = ds[i];
        text += (i+1) + '. [' + d.id + '] ' + (d.title || d.url || '—').slice(0, 60) + '\n   ' + d.created_at + '\n';
      }
    }
  } else if (action === 'pending') {
    const ac = (j.actions || []);
    if (!ac.length) {
      text = '🎯 Все actions закрыты! 🎉';
    } else {
      text = '🎯 Pending actions (' + ac.length + '):\n\n';
      for (let i = 0; i < Math.min(10, ac.length); i++) {
        const a = ac[i];
        text += (i+1) + '. [' + a.id + '] ' + (a.text || '—').slice(0, 80) + '\n';
      }
    }
  }
  out.push({ json: {
    user_id: user_id,
    chat_id: chat_id,
    formatted_text: text || '...'
  } });
}
return out;

// v6.0.26: prep for last digest lookup
const items = $input.all();
const out = [];
for (const item of items) {
  const j = item.json || {};
  out.push({json: {user_id: j.user_id || '261540559', chat_id: j.chat_id || '261540559', message_id: j.message_id || 0}});
}
return out;

// v6.0.26: build audio from last
const items = $input.all();
const out = [];
for (const item of items) {
  const j = item.json || {};
  const digests = j.digests || [];
  if (!digests.length) {
    out.push({json: {audio_text: '', title: 'Нет дайджестов', digest_id: 'empty', chat_id: j.chat_id || '261540559', empty: true}});
    continue;
  }
  const d = digests[0];
  const title = d.title || 'Дайджест';
  const summary = d.summary || [];
  const lines = ['Краткий обзор: ' + title, ''];
  for (let i = 0; i < Math.min(5, summary.length); i++) {
    lines.push((i+1) + '. ' + (typeof summary[i] === 'string' ? summary[i] : (summary[i].text || '')).substring(0, 600));
  }
  out.push({json: {audio_text: lines.join('\n').substring(0, 4500), digest_id: d.digest_id || 'd_last', title, chat_id: j.chat_id || '261540559', empty: false}});
}
return out;

// v6.0.27: dedupe via HTTP /seen_update + parse cmd
const _inItems = $input.all();
const _out = [];
for (const _it of _inItems) {
  const _itjson = _it.json || {};
  const _body = _itjson.body || _itjson;
  const _msg = _body.message || _body.edited_message || {};
  const _cb = _body.callback_query || null;
  const _update_id = _body.update_id || 0;
  let _deduped = false;
  if (_update_id) {
    try {
      const _r = await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://host.docker.internal:8080/seen_update',
        headers: {'Content-Type': 'application/json', 'X-Telegram-User-Id': '261540559'},
        body: {update_id: _update_id},
        timeout: 5000,
        returnFullResponse: false,
      });
      if (_r && _r.seen === true) {
        _deduped = true;
      }
    } catch (e) {
      // fail open
    }
  }
  if (_deduped) {
    _out.push({json: {deduped: true, update_id: _update_id, cmd: 'duplicate', _route: 'help'}});
    continue;
  }
  const user_id = (_cb && _cb.from && _cb.from.id) || (_msg.from && _msg.from.id) || 0;
  const chat_id = _cb ? (_cb.message && _cb.message.chat && _cb.message.chat.id) : (_msg.chat ? _msg.chat.id : null);
  const message_id = _cb ? (_cb.message && _cb.message.message_id) : _msg.message_id;
  const text = (_msg.text || _msg.caption || '').trim();
  let cmd = 'help', url = '', error_msg = '', _route = 'help';
  let media = null;
  let callback_id = null;
  let callback_data = null;
  let ack_text = '';
  if (_cb) {
    callback_id = _cb.id;
    callback_data = _cb.data;
  }
  if (_msg.voice) {
    media = {file_id: _msg.voice.file_id, mime: _msg.voice.mime_type || 'audio/ogg', kind: 'voice', file_name: 'voice.ogg', file_size: _msg.voice.file_size || 0, duration: _msg.voice.duration || 0};
  } else if (_msg.audio) {
    media = {file_id: _msg.audio.file_id, mime: _msg.audio.mime_type || 'audio/mpeg', kind: 'audio', file_name: _msg.audio.file_name || 'audio.mp3', file_size: _msg.audio.file_size || 0, duration: _msg.audio.duration || 0};
  } else if (_msg.video) {
    media = {file_id: _msg.video.file_id, mime: _msg.video.mime_type || 'video/mp4', kind: 'video', file_name: _msg.video.file_name || 'video.mp4', file_size: _msg.video.file_size || 0, duration: _msg.video.duration || 0};
  } else if (_msg.video_note) {
    media = {file_id: _msg.video_note.file_id, mime: 'video/mp4', kind: 'video_note', file_name: 'video_note.mp4', file_size: _msg.video_note.file_size || 0, duration: _msg.video_note.duration || 0};
  } else if (_msg.document) {
    const mime = _msg.document.mime_type || '';
    if (mime.startsWith('audio/') || mime.startsWith('video/')) {
      media = {file_id: _msg.document.file_id, mime: mime, kind: mime.startsWith('audio/') ? 'audio' : 'video', file_name: _msg.document.file_name || 'media', file_size: _msg.document.file_size || 0, duration: 0};
    }
  }
  if (_cb) {
    cmd = 'callback';
    _route = 'callback';
  } else if (media) {
    cmd = 'media';
    _route = 'media';
  } else if (text === '/stats' || text.startsWith('/stats@') || text === '/stats ') {
    cmd = 'stats_text';
    _route = 'callback';
    callback_data = 'stats';
  } else if (text === '/recent' || text.startsWith('/recent@') || text === '/recent ') {
    cmd = 'recent_text';
    _route = 'callback';
    callback_data = 'recent';
  } else if (text === '/pending' || text.startsWith('/pending@') || text === '/pending ') {
    cmd = 'pending_text';
    _route = 'callback';
    callback_data = 'pending';
  } else if (text === '/audio' || text.startsWith('/audio@') || text === '/audio ') {
    cmd = 'audio_text';
    _route = 'callback';
    callback_data = 'audio_last';
  } else if (text.startsWith('/help') || text.startsWith('/start') || text === '/help' || text === '/start') {
    cmd = 'help';
    _route = 'help';
  } else if (text) {
    const tokens = text.split(/\s+/);
    for (const tok of tokens) {
      let m = tok.match(/^https?:\/\/(?:[\w-]+\.)?youtu\.be\/([0-9A-Za-z_-]{11})/);
      if (m) { url = tok; cmd = 'fetch'; _route = 'fetch'; break; }
      m = tok.match(/^https?:\/\/(?:[\w-]+\.)?youtube\.com\/(?:watch\?v=|shorts\/|embed\/|v\/)([0-9A-Za-z_-]{11})/);
      if (m) { url = tok; cmd = 'fetch'; _route = 'fetch'; break; }
      m = tok.match(/^https?:\/\/(?:[\w-]+\.)?rutube\.ru\/(?:video|play\/embed)\/([0-9a-f]{32})/i);
      if (m) { url = tok; cmd = 'fetch'; _route = 'fetch'; break; }
      m = tok.match(/^https?:\/\/(?:[\w-]+\.)?vk(?:video)?\.(?:com|ru|net)\/(?:video|clip|wall)-(-?\d+_\d+)/i);
      if (m) { url = tok; cmd = 'fetch'; _route = 'fetch'; break; }
      m = tok.match(/^https?:\/\/(?:[\w-]+\.)?youtube\.com\/(?:@[^\/?#\s]+|channel\/[A-Za-z0-9_-]+|c\/[A-Za-z0-9_-]+|user\/[A-Za-z0-9_-]+)\/?$/);
      if (m) { url = tok; cmd = 'channel'; _route = 'channel'; break; }
    }
    if (cmd === 'help' && text.startsWith('http')) {
      cmd = 'invalid';
      _route = 'help';
      error_msg = 'Эта ссылка не поддерживается. Пришли ссылку на YouTube/Rutube/VK видео.';
    }
  }
  if (_route === 'fetch' && url) {
    if (/youtu\.be|youtube\.com/.test(url)) ack_text = 'Понял, обрабатываю YouTube видео...';
    else if (/rutube/.test(url)) ack_text = 'Понял, обрабатываю Rutube видео...';
    else if (/vk/.test(url)) ack_text = 'Понял, обрабатываю VK видео... Это может занять 5-7 минут (транскрибация)...';
    else ack_text = 'Понял, обрабатываю ссылку...';
  }
  _out.push({json: {user_id, chat_id, message_id, cmd, url, media, error_msg, raw: text, callback_id, callback_data, _route, ack_text}});
}
return _out;

// v6.0.21: read from /process_url (universal)
const parse = $('Code — Parse Command v6.0.27').first().json;
let url = parse.url;
if (parse.cmd === 'channel') {
  try {
    const latest = $('Code — Fetch latest from channel').first().json;
    if (latest && !latest.skip) {
      url = latest.full_url;
    }
  } catch (e) {}
}
const subs = $('HTTP /process_url').first().json;
const prof = $('HTTP /user_profile').first().json.profile || {};
return [{json: {
  chat_id: parse.chat_id,
  user_id: parse.user_id,
  message_id: parse.message_id,
  text: subs.text ? subs.text.slice(0, 8000) : '',
  system: '',
  user_profile: prof,
